import logging
import os

import boto3
import numpy as np
import pandas as pd

from resp_sp.breathing.functions_and_params import (
    calculate_rr_3,
)


def _download_sqa_model(model_name):
    LOCAL_MODEL_PATH = f"./model/{model_name}"
    os.makedirs(os.path.dirname(LOCAL_MODEL_PATH), exist_ok=True)
    if not os.path.exists(LOCAL_MODEL_PATH):
        s3 = boto3.client("s3")
        s3.download_file(
            "respiree-datasets",
            f"research/sqa_ml_model/{model_name}",
            LOCAL_MODEL_PATH,
        )
        logging.info(f"Model {model_name} downloaded successfully.")
    else:
        logging.info(f"Model {model_name} already exists locally.")


def calculate_rr_with_sqa(df_data: pd.DataFrame):

    _download_sqa_model(model_name="rf_sqa_160523.pkl")
    config = {
        "bool_output_rr_regardless_sqa": True,  # True - calculate rr as long as it can be computed regradless SQA good or bad
        "bool_predict_prob": False,  # True - predict probability, False - predict label
        "ml_model_fname": "rf_sqa_160523.pkl",  # rf_old_model_modified_label.pkl, rf_sqa_160523.pkl
    }

    # read_data = pd.DataFrame(
    #     read_data,
    #     columns=[
    #         "timestamp",
    #         "sensor1",
    #         "sensor2",
    #         "x_acc",
    #         "y_acc",
    #         "z_acc",
    #         "temp",
    #         "count1",
    #     ],
    # )
    
    # Below read_data needs to be changed accordingly based on the number of columns and meanings of each column
    # Below we assume that there are seven columns, including timestamp, optical sensor value, Euclidean of accelerometer values on three axis, accelerometer values
    # of x, y and z directions. Lastly will be the value of skin temperature
    data = df_data["sensor_1"]
    sensor2 = df_data["sensor_2"]
    x_acc = df_data["accl_x"]
    y_acc = df_data["accl_y"]
    z_acc = df_data["accl_z"]

    timestamp = np.arange(len(data))
    input_data = np.vstack([timestamp, data]).T

    cls_calculate_rr_3 = calculate_rr_3(
        input_data, sensor2, x_acc, y_acc, z_acc, config
    )
    temp_bpm_2_timestamp, temp_bpm_2_value, status, feature = cls_calculate_rr_3.run()

    return {"SQA_RR": temp_bpm_2_value, "SQA_status": status, "SQA_features": feature}
